/* ─── Dark Mode Design System ─── */
:root {
  --bg: #0d1117;
  --bg-elevated: #161b22;
  --bg-input: #0d1117;
  --border: #30363d;
  --border-focus: #58a6ff;
  --text: #e6edf3;
  --text-dim: #8b949e;
  --text-muted: #6e7681;
  --accent: #58a6ff;
  --orange: #d29922;
  --green: #3fb950;
  --red: #f85149;
  --purple: #bc8cff;
  --font: 'Inter', system-ui, -apple-system, sans-serif;
  --mono: 'JetBrains Mono', 'Fira Code', monospace;
}

* { box-sizing: border-box; margin: 0; padding: 0; }
html { font-size: 14px; }

body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

.app {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background: var(--bg);
}

/* ─── Header ─── */
.header {
  border-bottom: 1px solid var(--border);
  padding: 10px 20px;
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
  background: var(--bg-elevated);
}

.logo { display: flex; align-items: center; gap: 6px; }
.logo-icon { font-size: 18px; }
.header h1 { font-size: 17px; font-weight: 700; letter-spacing: -0.02em; color: var(--accent); }

.header .badge {
  font-size: 10px; color: var(--text-dim); background: var(--bg);
  border: 1px solid var(--border); border-radius: 5px;
  padding: 1px 6px; font-family: var(--mono); font-weight: 500;
}

.subtitle { font-size: 12px; color: var(--text-muted); margin-left: 2px; }

.header-stats { margin-left: auto; display: flex; gap: 10px; }
.header-stats .stat { font-size: 11px; color: var(--text-muted); }
.header-stats .num { color: var(--text-dim); font-weight: 600; font-family: var(--mono); }

/* ─── Tabs ─── */
.tabs {
  display: flex;
  flex-wrap: wrap;
